// Double-submit CSRF: value lives in a non-HttpOnly cookie AND is echoed in a header.
// The server checks the two match. An attacker on another origin cannot read the
// cookie value to forge the header (same-origin policy blocks reading it).

import crypto from 'node:crypto';
import type { Request, Response, NextFunction } from 'express';

export function issueCsrfToken(_req: Request, res: Response, next: NextFunction) {
  const token = crypto.randomBytes(32).toString('base64url');
  // Readable by JS so the SPA can copy it into the X-CSRF-Token header.
  // NOT HttpOnly on purpose; the *session* cookie stays HttpOnly.
  res.cookie('csrf', token, { secure: true, sameSite: 'lax', path: '/' });
  next();
}

export function verifyCsrf(req: Request, res: Response, next: NextFunction) {
  if (['GET', 'HEAD', 'OPTIONS'].includes(req.method)) return next();
  const cookieToken = req.cookies['csrf'];
  const headerToken = req.get('X-CSRF-Token');
  if (
    !cookieToken ||
    !headerToken ||
    cookieToken.length !== headerToken.length ||
    !crypto.timingSafeEqual(Buffer.from(cookieToken), Buffer.from(headerToken))
  ) {
    return res.status(403).json({ error: 'csrf_failed' });
  }
  next();
}

import type { Request, Response, NextFunction } from 'express';
import { redis } from './redis';

const SESSION_TTL_SECONDS = 60 * 30; // 30 min sliding window

export interface SessionData {
  userId: string;
  roles: string[];
  createdAt: number;
}

export async function requireSession(req: Request, res: Response, next: NextFunction) {
  const sid = req.cookies['__Host-sid'];
  if (!sid) return res.status(401).json({ error: 'no_session' });

  const key = `sess:${sid}`;
  const raw = await redis.get(key);
  if (!raw) return res.status(401).json({ error: 'session_expired' });

  const session = JSON.parse(raw) as SessionData;

  // Sliding expiry: renew TTL on activity so active users stay logged in.
  await redis.expire(key, SESSION_TTL_SECONDS);

  // Attach principal; downstream authorization uses this, not the cookie.
  (req as Request & { user: SessionData }).user = session;
  next();
}

// Logout: single line, instantly effective on the next request.
export async function destroySession(sid: string) {
  await redis.del(`sess:${sid}`);
}

// Force-logout a user everywhere: track sids per user in a set.
export async function destroyAllForUser(userId: string) {
  const sids = await redis.smembers(`user-sessions:${userId}`);
  if (sids.length) await redis.del(...sids.map((s) => `sess:${s}`));
  await redis.del(`user-sessions:${userId}`);
}

// Refresh rotation with reuse detection (server side).
// Each refresh token belongs to a 'family'; consuming one issues the next.

interface RefreshRecord {
  tokenHash: string;   // store only a hash, never the raw token
  familyId: string;
  used: boolean;
  expiresAt: number;
}

async function rotateRefreshToken(presentedRaw: string) {
  const hash = sha256(presentedRaw);
  const rec = await store.findByHash(hash);

  if (!rec || rec.expiresAt < Date.now()) {
    throw new AuthError('invalid_grant');
  }

  // Reuse detection: an already-used token means the family is compromised.
  if (rec.used) {
    await store.revokeFamily(rec.familyId); // kill every token in the chain
    throw new AuthError('token_reuse_detected'); // force full re-login
  }

  // Normal path: mark old as used, mint a fresh pair in the same family.
  await store.markUsed(rec.tokenHash);
  const newRefreshRaw = randomToken();
  await store.save({
    tokenHash: sha256(newRefreshRaw),
    familyId: rec.familyId,
    used: false,
    expiresAt: Date.now() + REFRESH_TTL_MS,
  });

  return { accessToken: mintAccessToken(rec), refreshToken: newRefreshRaw };
}

