import express from 'express';
import { redis } from './redis';
import { oidc } from './oidc'; // configured against Keycloak realm 'acme'
import crypto from 'node:crypto';

const app = express();

app.get('/bff/login', async (req, res) => {
  const { url, codeVerifier, state } = await oidc.buildAuthUrl(); // PKCE S256
  await redis.set(`pkce:${state}`, codeVerifier, 'EX', 300);
  res.redirect(url); // -> Keycloak /auth
});

app.get('/bff/callback', async (req, res) => {
  const { code, state } = req.query as { code: string; state: string };
  const codeVerifier = await redis.get(`pkce:${state}`);
  if (!codeVerifier) return res.status(400).send('bad_state');

  const tokens = await oidc.exchangeCode(code, codeVerifier); // access + refresh + id
  const sid = crypto.randomBytes(32).toString('base64url');
  await redis.set(`sess:${sid}`, JSON.stringify(tokens), 'EX', 1800);
  // Track sid under the subject so back-channel logout can find it.
  await redis.sadd(`kc-sub:${tokens.claims.sub}`, sid);

  res.cookie('__Host-sid', sid, {
    httpOnly: true, secure: true, sameSite: 'lax', path: '/',
  });
  res.redirect('/');
});

// Keycloak calls this directly (server-to-server) when the IdP session ends.
app.post('/bff/backchannel-logout', express.urlencoded({ extended: false }), async (req, res) => {
  const sub = await oidc.validateLogoutToken(req.body.logout_token); // verify signature + claims
  const sids = await redis.smembers(`kc-sub:${sub}`);
  if (sids.length) await redis.del(...sids.map((s) => `sess:${s}`));
  await redis.del(`kc-sub:${sub}`);
  res.sendStatus(200);
});

