import express, { Request, Response, NextFunction } from 'express';
import cookieParser from 'cookie-parser';
import crypto from 'node:crypto';
import { redis } from './redis';

const app = express();
app.use(cookieParser());
app.use(express.json());

const SESSION_TTL = 60 * 30; // 30 min
type Session = { userId: string; roles: string[] };

function newToken() {
  return crypto.randomBytes(32).toString('base64url');
}

// --- Login: create session + set cookies ---
app.post('/login', async (req: Request, res: Response) => {
  const user = await authenticate(req.body.username, req.body.password);
  if (!user) return res.status(401).json({ error: 'bad_credentials' });

  const sid = newToken();
  const session: Session = { userId: user.id, roles: user.roles };
  await redis.set(`sess:${sid}`, JSON.stringify(session), 'EX', SESSION_TTL);
  await redis.sadd(`user-sessions:${user.id}`, sid);

  const csrf = newToken();
  await redis.set(`csrf:${sid}`, csrf, 'EX', SESSION_TTL);

  res.cookie('__Host-sid', sid, {
    httpOnly: true, secure: true, sameSite: 'lax', path: '/',
  });
  // Readable by the SPA on purpose so it can echo it in a header.
  res.cookie('csrf', csrf, { secure: true, sameSite: 'lax', path: '/' });
  res.json({ ok: true });
});

// --- Require an authenticated session ---
async function requireSession(req: Request, res: Response, next: NextFunction) {
  const sid = req.cookies['__Host-sid'];
  if (!sid) return res.status(401).json({ error: 'no_session' });
  const raw = await redis.get(`sess:${sid}`);
  if (!raw) return res.status(401).json({ error: 'expired' });
  await redis.expire(`sess:${sid}`, SESSION_TTL); // sliding window
  (req as any).sid = sid;
  (req as any).user = JSON.parse(raw) as Session;
  next();
}

// --- CSRF double-submit check on state-changing methods ---
async function verifyCsrf(req: Request, res: Response, next: NextFunction) {
  if (['GET', 'HEAD', 'OPTIONS'].includes(req.method)) return next();
  const sid = (req as any).sid as string;
  const expected = await redis.get(`csrf:${sid}`);
  const cookieTok = req.cookies['csrf'];
  const headerTok = req.get('X-CSRF-Token');
  if (
    !expected || !cookieTok || !headerTok ||
    cookieTok !== expected ||
    headerTok.length !== cookieTok.length ||
    !crypto.timingSafeEqual(Buffer.from(headerTok), Buffer.from(cookieTok))
  ) {
    return res.status(403).json({ error: 'csrf_failed' });
  }
  next();
}

app.use(requireSession, verifyCsrf);

// --- Instant logout ---
app.post('/logout', async (req: Request, res: Response) => {
  const sid = (req as any).sid as string;
  const user = (req as any).user as Session;
  await redis.del(`sess:${sid}`, `csrf:${sid}`);
  await redis.srem(`user-sessions:${user.userId}`, sid);
  res.clearCookie('__Host-sid', { path: '/' });
  res.clearCookie('csrf', { path: '/' });
  res.json({ ok: true });
});

