import express, { Request, Response } from 'express';
import cookieParser from 'cookie-parser';
import crypto from 'node:crypto';
import { redis } from './redis';
import { oidc } from './oidc'; // wraps Keycloak endpoints for realm 'acme'

const app = express();
app.use(cookieParser());

const SESS_TTL = 60 * 60; // 1h session window
type Tokens = { access: string; refresh: string; accessExp: number; sub: string };

const rnd = () => crypto.randomBytes(32).toString('base64url');

// 1) Start login: build PKCE + state, redirect to Keycloak.
app.get('/bff/login', async (_req: Request, res: Response) => {
  const { url, codeVerifier, state } = await oidc.buildAuthUrl(); // S256
  await redis.set(`pkce:${state}`, codeVerifier, 'EX', 300);
  res.redirect(url);
});

// 2) Callback: exchange code, store tokens server-side, set opaque cookie.
app.get('/bff/callback', async (req: Request, res: Response) => {
  const { code, state } = req.query as { code: string; state: string };
  const verifier = await redis.get(`pkce:${state}`);
  if (!verifier) return res.status(400).send('bad_state');
  await redis.del(`pkce:${state}`);

  const t = await oidc.exchangeCode(code, verifier);
  const sid = rnd();
  const tokens: Tokens = {
    access: t.access_token,
    refresh: t.refresh_token,
    accessExp: Date.now() + t.expires_in * 1000,
    sub: t.claims.sub,
  };
  await redis.set(`sess:${sid}`, JSON.stringify(tokens), 'EX', SESS_TTL);
  await redis.sadd(`kc-sub:${tokens.sub}`, sid);

  res.cookie('__Host-sid', sid, {
    httpOnly: true, secure: true, sameSite: 'lax', path: '/',
  });
  res.redirect('/');
});

// Load + refresh (with rotation) as needed.
async function getFreshTokens(sid: string): Promise<Tokens | null> {
  const raw = await redis.get(`sess:${sid}`);
  if (!raw) return null;
  let tokens = JSON.parse(raw) as Tokens;
  if (Date.now() < tokens.accessExp - 5000) return tokens; // still valid

  const refreshed = await oidc.refresh(tokens.refresh); // rotates refresh token
  tokens = {
    access: refreshed.access_token,
    refresh: refreshed.refresh_token, // new refresh -> rotation
    accessExp: Date.now() + refreshed.expires_in * 1000,
    sub: tokens.sub,
  };
  await redis.set(`sess:${sid}`, JSON.stringify(tokens), 'EX', SESS_TTL);
  return tokens;
}

// 3) Proxy a downstream call; attach the real token server-side only.
app.get('/bff/api/orders', async (req: Request, res: Response) => {
  const sid = req.cookies['__Host-sid'];
  if (!sid) return res.status(401).json({ error: 'no_session' });
  const tokens = await getFreshTokens(sid);
  if (!tokens) return res.status(401).json({ error: 'expired' });

  const upstream = await fetch('https://api.acme.com/orders', {
    headers: { Authorization: `Bearer ${tokens.access}` },
  });
  const body = await upstream.text();
  res.status(upstream.status).type('application/json').send(body);
});

// 4) Back-channel logout from Keycloak.
app.post('/bff/backchannel-logout', express.urlencoded({ extended: false }), async (req, res) => {
  const sub = await oidc.validateLogoutToken(req.body.logout_token);
  const sids = await redis.smembers(`kc-sub:${sub}`);
  if (sids.length) await redis.del(...sids.map((s) => `sess:${s}`));
  await redis.del(`kc-sub:${sub}`);
  res.sendStatus(200);
});

export default app;
